# For each cell (r,c) not on a segment:
# e = r-c, d = r+c
# Check if there exists a segment with d_s < d that covers e (e_min_s <= e <= e_max_s)
# AND a segment with d_s > d that covers e
# If both exist, the cell is filled.

# But I also need to handle parity: a segment at even d has even e values,
# and a cell at odd d has odd e values. The segment "covers" the cell's e 
# even if the segment's e values are the opposite parity, as long as the cell's e 
# falls within [e_min_s, e_max_s].

def solve_v2(grid):
    import numpy as np
    grid = np.array(grid)
    H, W = grid.shape
    bg = 8
    colors = set(int(x) for x in grid.flat) - {bg}
    if not colors:
        return grid.tolist()
    color = colors.pop()

    from collections import defaultdict
    diag_cells = defaultdict(list)
    for r in range(H):
        for c in range(W):
            if grid[r,c] == color:
                d = r + c
                e = r - c
                diag_cells[d].append(e)

    segments = []
    for d in sorted(diag_cells):
        es = sorted(diag_cells[d])
        groups = []
        cur_group = [es[0]]
        for i in range(1, len(es)):
            if es[i] - es[i-1] == 2:
                cur_group.append(es[i])
            else:
                groups.append(cur_group)
                cur_group = [es[i]]
        groups.append(cur_group)
        for g in groups:
            segments.append((d, min(g), max(g)))

    output = grid.copy()

    for r in range(H):
        for c in range(W):
            if grid[r,c] != bg:
                continue
            d = r + c
            e = r - c

            has_left = False
            has_right = False
            for sd, se_min, se_max in segments:
                if se_min <= e <= se_max:
                    if sd < d:
                        has_left = True
                    elif sd > d:
                        has_right = True

            if has_left and has_right:
                output[r,c] = 2

    return output.tolist()

